const CHANNELS = ["Bazooka Vault", "Bazooka Breaks", "Orbital Society"];
// Effective channel for a stream. BigU always counts as Bazooka Breaks (except
// Orbital Society, which is tracked separately). For everyone else, an explicit
// channel wins, otherwise Bazooka Vault.
function channelOf(s){
  const isBigU = s && (s.breaker||"").toLowerCase().replace(/\s+/g,"") === "bigu";
  if (isBigU) return s.channel === "Orbital Society" ? "Orbital Society" : "Bazooka Breaks";
  if (s && s.channel) return s.channel;
  return "Bazooka Vault";
}

// Canonical weapon names — collapse case/punctuation dupes (ALT==Alt, FIRE==Fire, etc.)
// Search synonyms. Collectors say "auto", the checklist says "Inspired Ink" — and expecting someone
// to type the exact printed treatment name to find their card is a bad search box.
//
// These are folded into the search INDEX (one string per card, built once), not applied per keystroke,
// so matching stays a plain substring test and costs nothing at type time. Keys are matched as
// substrings of the treatment, so "inspired ink" catches "Magic Gum Inspired Ink" too.
const SEARCH_SYNONYMS = {
  "inspired ink": ["auto", "autograph", "signed", "signature"],
  "linoleum":     ["lino"],
  "battlefoil":   ["foil", "bf"],
  "refractor":    ["refract"],
  "prismatic":    ["prizm", "prism"],
  "home team discount": ["htd", "discount"],
  "plays":        ["play"],
  "secret 1/1":   ["1of1", "1 of 1", "one of one", "oneofone"],
  "super":        ["superfoil", "super foil"],
};
// Any synonym that applies to a card, as a flat string to append to its search text.
function synonymsFor(c) {
  const hay = [c.treatment, c.notation, c.variation].filter(Boolean).join(" ").toLowerCase();
  let out = "";
  for (const key in SEARCH_SYNONYMS) {
    if (hay.includes(key)) out += " " + SEARCH_SYNONYMS[key].join(" ");
  }
  return out;
}

const WEAPON_CANON = { alt:"Alt", fire:"Fire", glow:"Glow", gum:"Gum", hex:"Hex", ice:"Ice", steel:"Steel", super:"Super", brawl:"Brawl", cyber:"Cyber", medal:"Medal", metallic:"Metallic" };
function canonWeapon(w) {
  if (!w) return w;
  const k = String(w).trim().toLowerCase();
  return WEAPON_CANON[k] || (String(w).trim().charAt(0).toUpperCase() + String(w).trim().slice(1).toLowerCase());
}
// Preferred display order for weapon dropdowns
const WEAPON_ORDER = ["Brawl","Steel","Fire","Ice","Glow","Hex","Gum","Super","Alt","Cyber","Medal","Metallic"];
function sortWeapons(list) {
  return [...list].sort((a,b) => {
    const ia = WEAPON_ORDER.indexOf(a), ib = WEAPON_ORDER.indexOf(b);
    if (ia === -1 && ib === -1) return a.localeCompare(b);
    if (ia === -1) return 1; if (ib === -1) return -1;
    return ia - ib;
  });
}

// ── Gzip helpers for the card snapshot (cuts ~13MB → ~1.5MB on first load) ──
function _loadPako() {
  return new Promise((resolve, reject) => {
    if (window.pako) return resolve(window.pako);
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/pako/2.1.0/pako.min.js";
    s.onload = () => resolve(window.pako);
    s.onerror = () => reject(new Error("pako load failed"));
    document.body.appendChild(s);
  });
}
// Write the card array to Storage as gzip (boba_checklist.json.gz). Returns true on success.
async function writeCardSnapshot(all, cacheSeconds) {
  const pako = await _loadPako();
  const gz = pako.gzip(JSON.stringify(all));
  const blob = new Blob([gz], { type: "application/json" });
  const gzRef = ref(storage, "card_data/boba_checklist.json.gz");
  await uploadBytes(gzRef, blob, { contentType: "application/json", contentEncoding: "identity", cacheControl: `public,max-age=${cacheSeconds||300}` });
  return true;
}
// Read + decompress the gz snapshot. Returns array or null.
async function readCardSnapshot(bust) {
  const pako = await _loadPako();
  const url = await getDownloadURL(ref(storage, "card_data/boba_checklist.json.gz"));
  const r = await fetch(url + (bust ? ((url.includes("?")?"&":"?") + "v=" + Date.now()) : ""));
  const buf = new Uint8Array(await r.arrayBuffer());
  const text = pako.ungzip(buf, { to: "string" });
  const arr = JSON.parse(text);
  return Array.isArray(arr) ? arr : null;
}

// ── IndexedDB cache (localStorage caps ~5MB; the 12MB card list needs IndexedDB) ──
function _idbOpen() {
  return new Promise((resolve, reject) => {
    try {
      const req = indexedDB.open("bazooka_cards", 1);
      req.onupgradeneeded = () => { try { req.result.createObjectStore("kv"); } catch(e){} };
      req.onsuccess = () => resolve(req.result);
      req.onerror = () => reject(req.error);
    } catch(e) { reject(e); }
  });
}
async function idbGetCards() {
  try {
    const dbi = await _idbOpen();
    return await new Promise((resolve) => {
      const tx = dbi.transaction("kv", "readonly");
      const rq = tx.objectStore("kv").get("cards_v3");
      rq.onsuccess = () => resolve(rq.result || null);
      rq.onerror = () => resolve(null);
    });
  } catch(e) { return null; }
}
async function idbSetCards(cards, ts) {
  try {
    const dbi = await _idbOpen();
    await new Promise((resolve) => {
      const tx = dbi.transaction("kv", "readwrite");
      tx.objectStore("kv").put({ cards, ts: ts||Date.now() }, "cards_v3");
      tx.oncomplete = () => resolve();
      tx.onerror = () => resolve();
    });
  } catch(e) {}
}
async function idbClearCards() {
  try {
    const dbi = await _idbOpen();
    await new Promise((resolve) => {
      const tx = dbi.transaction("kv", "readwrite");
      tx.objectStore("kv").delete("cards_v3");
      tx.oncomplete = () => resolve();
      tx.onerror = () => resolve();
    });
  } catch(e) {}
}

const FLAT_RATE_CHANNELS = []; // no flat-rate channels currently
const FLAT_RATE_BREAKERS = []; // all breakers use standard tiered commission

function getRate(s) {
  if (s.commissionOverride !== "" && s.commissionOverride != null) return parseFloat(s.commissionOverride)/100;
  if (s.isEvent) return 0.15;
  const newBuyerBonus = (parseInt(s.newBuyers)||0) >= 5 ? 0.05 : 0;
  const isFlat = (s.channel && FLAT_RATE_CHANNELS.includes(s.channel)) || (!s.channel && FLAT_RATE_BREAKERS.includes(s.breaker));
  if (isFlat) return Math.min(0.55, 0.50 + newBuyerBonus);
  if (s.binOnly) return 0.35;
  const mm = parseFloat(s.marketMultiple)||0;
  const base = mm>=1.8?0.55:mm>=1.7?0.50:mm>=1.6?0.45:mm>=1.5?0.40:0.35;
  return Math.min(0.60, base + newBuyerBonus);
}
