function athleteSport(name) {
  if (!name) return null;
  return ATHLETE_SPORT[name.trim()] || ATHLETE_SPORT[name] || null;
}

function BobaCardImpl({ c, isOwned, ownedQty, flippedCard, setFlippedCard, toggleOwned, setOwnedQty, toggleWant, wantList, WEAPON_COLORS, isAdmin, onDelete, onComp, onImageUpload, onImageClear, onLotEdit, lotCount=0, onCardActivity, onExpand, myScanPhoto, cardWidthHint=200, kidGroups=[], kidTags=null, onAssignKid, onSell, foundInMap={} }) {
  const wc = WEAPON_COLORS[canonWeapon(c.weapon)] || "#444";
  // Image priority: official admin imageUrl → my own private scan photo → coming-soon placeholder.
  // Foil/shine overlays only apply to the official art, not to a raw scan photo.
  const _officialImg = c.imageUrl;
  const _displayImg = _officialImg || myScanPhoto || null;
  const _isScanImg = !_officialImg && !!myScanPhoto;
  const isFlipped = flippedCard === c.id;
  const [bioOpen, setBioOpen] = useState(false);
  const _canHover = typeof window !== "undefined" && window.matchMedia && window.matchMedia("(hover: hover)").matches;
  const qty = ownedQty || 0;
  const isWanted = !!(wantList && wantList[c.id]);
  const cardRef = useRef(null);
  // PERF: this used to create a ResizeObserver PER CARD and call setCardW() on mount, forcing a
  // second render of every tile in the grid. With ~100 tiles that's 100 observers and 100 extra
  // renders every time the list changes (i.e. on every search). The card width only matters for
  // one thing — hiding some detail on narrow tiles — so derive it from the grid density instead
  // of measuring each card individually.
  const isSmallCard = cardWidthHint < 165;
  const foilRef = useRef(null);
  const glareRef = useRef(null);
  const animRef = useRef(null);
  const currentTilt = useRef({ x:0, y:0 });
  const targetTilt  = useRef({ x:0, y:0 });
  const isHovering  = useRef(false);

  // No shine for paper (non-foil base) cards and Plays (but Bonus Plays still shine)
  const treatment = (c.treatment||"").toLowerCase();
  const cardType  = (c.cardType||c.variation||"").toLowerCase();
  const noShine = treatment === "base" ||
                  treatment === "paper" ||
                  treatment === "paper plays" ||
                  treatment === "play" ||
                  treatment === "plays" ||
                  treatment === "hot dog" ||
                  treatment.includes("hot dog") ||
                  (treatment.includes("play") && !treatment.includes("bonus")) ||
                  (String(c.cardNum||"").toUpperCase().startsWith("PL") && !String(c.cardNum||"").toUpperCase().startsWith("BPL"));

  // Pixel/cyber sparkle foil for Helmet Icon cards
  const isPixelFoil    = treatment.includes("helmet icon");
  const isMetallicFoil = treatment.includes("metallic") || treatment.includes("inspired ink metallic");
  // Cracked-ice / shattered-glass foil for Alpha Blast set cards
  const _setLower = (c.setName||"").toLowerCase();
  const _iceIsPaper = /\b(paper|base)\b/.test(treatment) && !treatment.includes("battlefoil") && !treatment.includes("foil");
  const isIceFoil = (_setLower.includes("alpha blast") || _setLower.includes("blast")) && !_iceIsPaper;
  // Base / paper cards have NO foil shine — only true foil treatments shimmer
  const _isPaperBase = /\b(paper|base)\b/.test(treatment) && !treatment.includes("battlefoil") && !treatment.includes("foil");
  const isFoilTreatment = !_isPaperBase && /foil|linoleum|metallic|holo|prizm|refractor|chrome|sparkle|shimmer|rainbow|gold|silver|inspired ink|battlefoil/.test(treatment);
  const pixelRef = useRef(null);
  const pixelAnim = useRef(null);
  const mousePos = useRef({ x:0.5, y:0.5 });

  const pixelCanvasRef = useRef(null);
  const pixelAnimRef = useRef(null);
  const metallicRef = useRef(null);
  const iceRef = useRef(null);
  const iceShardsRef = useRef(null); // cached shard SVG data URL

  // Build a dense field of iridescent angular shards once (cached), matching the cracked-ice look.
  // Cracked-ice foil: layered angular facet gradients (no SVG dependency) + icy sheen.
  // How the foil looks when nobody's hovering. Without this the card would be flat until you mouse
  // over it, and most cards in a grid are never hovered at all.
  function _iceRest() {
    return [
      `linear-gradient(115deg,
         transparent 30%,
         hsla(190, 90%, 92%, 0.16) 43%,
         hsla(280, 95%, 95%, 0.34) 50%,
         hsla(45, 90%, 92%, 0.16) 57%,
         transparent 70%)`,
      `linear-gradient(95deg,
         hsla(200, 85%, 70%, 0.10),
         hsla(280, 90%, 78%, 0.13) 35%,
         hsla(20, 90%, 78%, 0.13) 65%,
         hsla(120, 85%, 70%, 0.10))`,
    ].join(", ");
  }
  // Prismatic sheen for Alpha Blast cards.
  //
  // The previous effect stacked four repeating-linear-gradients at 63/112/158/9 degrees to fake
  // "cracked ice". Repeating gradients are inherently REGULAR, though, and real shattered glass is
  // irregular — so what it actually produced was a fine cross-hatch that read as moiré on a small
  // card tile, not as ice. CSS can't really do irregular facets; that wants an SVG or a texture.
  //
  // So instead: a clean prismatic sweep that tracks the cursor. Fewer layers, no texture, and it's
  // the look people already read as "premium card" — refractor, prizm, that family.
  function drawIceFoil(x, y) {
    if (!iceRef.current) return;
    const el = iceRef.current;

    // Hue rotates as the cursor moves across the card, so tilting it walks the rainbow.
    const hue = (x * 300 + y * 60) % 360;
    // The sheen band travels with the cursor; the angle leans slightly so it doesn't feel static.
    const band  = 20 + (x * 0.65 + y * 0.35) * 60;   // 20% .. 80%
    const angle = 100 + x * 40;

    el.style.backgroundImage = [
      // The bright specular band — the thing your eye actually follows.
      `linear-gradient(${angle}deg,
         transparent ${band - 26}%,
         hsla(${(hue + 300) % 360}, 90%, 88%, 0.20) ${band - 12}%,
         hsla(${hue}, 100%, 96%, 0.60) ${band}%,
         hsla(${(hue + 60) % 360}, 90%, 88%, 0.20) ${band + 12}%,
         transparent ${band + 26}%)`,
      // A wide, soft rainbow wash underneath so the whole card shifts colour, not just the band.
      `linear-gradient(${angle - 20}deg,
         hsla(${(hue + 200) % 360}, 85%, 70%, 0.13),
         hsla(${(hue + 280) % 360}, 90%, 78%, 0.16) 35%,
         hsla(${(hue + 20) % 360}, 90%, 78%, 0.16) 65%,
         hsla(${(hue + 120) % 360}, 85%, 70%, 0.13))`,
      // A gentle bloom under the cursor, so the card feels lit from where you're pointing.
      `radial-gradient(circle at ${(x*100).toFixed(0)}% ${(y*100).toFixed(0)}%,
         rgba(255,255,255,0.22), transparent 55%)`,
    ].join(", ");
    el.style.opacity = "1";
  }

  function drawMetallicFoil(x, y) {
    if (!metallicRef.current) return;
    const el = metallicRef.current;
    // Horizontal bands of light that shift with mouse Y
    // Rainbow color shift based on mouse X
    const hue  = (x * 240) % 360;
    const hue2 = (hue + 40) % 360;
    const band = y * 100; // band position as %
    el.style.background = [
      // Main bright horizontal sweep band
      `linear-gradient(to bottom,
        transparent ${Math.max(0,band-30)}%,
        hsla(${hue},60%,95%,0.15) ${Math.max(0,band-15)}%,
        hsla(${hue2},80%,98%,0.55) ${band}%,
        hsla(${hue},60%,95%,0.15) ${Math.min(100,band+15)}%,
        transparent ${Math.min(100,band+30)}%)`,
      // Subtle horizontal stripe texture
      `repeating-linear-gradient(to bottom,
        transparent 0px,
        rgba(255,255,255,0.04) 1px,
        transparent 2px,
        rgba(255,255,255,0.02) 3px,
        transparent 4px)`,
      // Color wash based on X
      `linear-gradient(to right,
        hsla(${(hue+180)%360},70%,60%,0.12),
        hsla(${hue},80%,80%,0.18) ${x*100}%,
        hsla(${hue2},70%,60%,0.12))`,
    ].join(", ");
    el.style.opacity = "1";
    el.style.mixBlendMode = "screen";
  }

  function drawPixelFoil(x, y) {
    if (!pixelRef.current || !isPixelFoil) return;
    const el = pixelRef.current;
    const hue  = (x * 180 + y * 90 + Date.now() * 0.05) % 360;
    const hue2 = (hue + 80) % 360;
    const hue3 = (hue + 160) % 360;
    el.style.background = [
      `radial-gradient(ellipse 60% 40% at ${x*100}% ${y*100}%, hsla(${hue},100%,75%,0.5) 0%, transparent 70%)`,
      `radial-gradient(ellipse 50% 60% at ${(1-x)*100}% ${y*100}%, hsla(${hue2},100%,70%,0.4) 0%, transparent 65%)`,
      `radial-gradient(ellipse 40% 50% at ${x*100}% ${(1-y)*100}%, hsla(${hue3},100%,75%,0.35) 0%, transparent 60%)`,
      `repeating-linear-gradient(${x*180}deg, hsla(${hue},100%,70%,0.12) 0px, transparent 4px, hsla(${hue2},100%,65%,0.08) 8px, transparent 12px)`,
      `repeating-linear-gradient(${x*180+90}deg, hsla(${hue3},100%,70%,0.10) 0px, transparent 4px, hsla(${hue},100%,65%,0.06) 8px, transparent 12px)`,
    ].join(", ");
    el.style.opacity = "1";
    el.style.mixBlendMode = "screen";
  }

  // Animate pixel foil continuously when hovered
  useEffect(() => {
    if (!isPixelFoil) return;
    return () => { if (pixelAnimRef.current) cancelAnimationFrame(pixelAnimRef.current); };
  }, [isPixelFoil]);

  function startPixelAnim(x, y) {
    if (!isPixelFoil) return;
    if (pixelAnimRef.current) cancelAnimationFrame(pixelAnimRef.current);
    function tick() {
      drawPixelFoil(x, y);
      pixelAnimRef.current = requestAnimationFrame(tick);
    }
    tick();
  }

  function stopPixelAnim() {
    if (pixelAnimRef.current) cancelAnimationFrame(pixelAnimRef.current);
    pixelAnimRef.current = null;
    if (pixelRef.current) pixelRef.current.style.opacity = "0";
  }


  function startAnimation() { if (animRef.current) return; animRef.current = requestAnimationFrame(animate); }
  function onMouseMove(e) {
    if (isFlipped) return;
    if (!_canHover) return; // touch devices: no hover tilt/foil (it'd get stuck with no mouse-leave)
    const rect = cardRef.current?.getBoundingClientRect();
    if (!rect) return;
    const x = (e.clientX - rect.left) / rect.width;
    const y = (e.clientY - rect.top)  / rect.height;
    targetTilt.current = { x: (y - 0.5) * 28, y: (x - 0.5) * -28 };
    if (!noShine) {
      if (isPixelFoil) {
        startPixelAnim(x, y);
      } else if (isIceFoil) {
        drawIceFoil(x, y);
      } else if (isMetallicFoil) {
        drawMetallicFoil(x, y);
      } else {
        if (foilRef.current) { foilRef.current.style.setProperty("--foilpos",`${x*100}% ${y*100}%`); foilRef.current.style.opacity = "1"; }
        if (glareRef.current) { glareRef.current.style.background = `radial-gradient(ellipse at ${x*100}% ${y*100}%, rgba(255,255,255,0.22) 0%, transparent 60%)`; glareRef.current.style.opacity = "1"; }
      }
    }
    startAnimation();
  }
  function onMouseLeave() {
    isHovering.current = false; targetTilt.current = { x:0, y:0 };
    if (foilRef.current) foilRef.current.style.opacity = "0";
    if (glareRef.current) glareRef.current.style.opacity = "0";
    if (isPixelFoil) stopPixelAnim();
    else if (isIceFoil && iceRef.current) { iceRef.current.style.backgroundImage = _iceRest(); iceRef.current.style.opacity = "0.75"; }
    else if (isMetallicFoil && metallicRef.current) metallicRef.current.style.opacity = "0";
    else if (pixelRef.current) pixelRef.current.style.opacity = "0";
    startAnimation();
  }
  function onMouseEnter() { isHovering.current = true; startAnimation(); }
  function animate() {
    const cur = currentTilt.current, tgt = targetTilt.current;
    cur.x += (tgt.x - cur.x) * 0.1; cur.y += (tgt.y - cur.y) * 0.1;
    if (cardRef.current && !isFlipped) { cardRef.current.style.transition = "box-shadow 0.2s ease"; cardRef.current.style.transform = `perspective(600px) rotateX(${cur.x}deg) rotateY(${cur.y}deg) scale3d(1.04,1.04,1.04)`; }
    if (Math.abs(tgt.x-cur.x)>0.05||Math.abs(tgt.y-cur.y)>0.05||isHovering.current) { animRef.current = requestAnimationFrame(animate); }
    else { animRef.current = null; cur.x = 0; cur.y = 0; if(cardRef.current && !isFlipped) { cardRef.current.style.transition = ""; cardRef.current.style.transform = ""; } }
  }
  function handleClick() {
    if (animRef.current) { cancelAnimationFrame(animRef.current); animRef.current = null; }
    currentTilt.current = { x:0, y:0 }; targetTilt.current = { x:0, y:0 };
    if (foilRef.current) foilRef.current.style.opacity = "0";
    if (glareRef.current) glareRef.current.style.opacity = "0";
    if (cardRef.current) { cardRef.current.style.transition = ""; cardRef.current.style.transform = ""; }
    isHovering.current = false;
    if (onExpand) { onExpand(c); return; }
    setFlippedCard(!isFlipped ? c.id : null);
  }

  const QtyControls = () => (
    <div style={{ display:"flex", alignItems:"center", gap:4 }} onClick={e=>e.stopPropagation()}>
      <button onClick={()=>setOwnedQty(c.id, Math.max(0, qty-1))} style={{ background:"#1a1a1a", border:"1px solid var(--bz-line-2)", color:"var(--bz-ink-2)", borderRadius:5, width:22, height:22, fontSize:13, cursor:"pointer", fontFamily:"inherit", lineHeight:1, display:"flex", alignItems:"center", justifyContent:"center" }}>{"\u2212"}</button>
      <input
        type="number" inputMode="numeric" min="0" value={qty}
        onClick={e=>{e.stopPropagation(); e.target.select();}}
        onChange={e=>{ const v=parseInt(e.target.value,10); setOwnedQty(c.id, isNaN(v)?0:Math.max(0,v)); }}
        style={{ width:38, height:22, fontSize:12, fontWeight:700, color:qty>0?"#4ade80":"#888", textAlign:"center", background:"#1a1a1a", border:"1px solid var(--bz-line-2)", borderRadius:5, fontFamily:"inherit", padding:0, MozAppearance:"textfield" }}
      />
      <button onClick={()=>setOwnedQty(c.id, qty+1)} style={{ background:"#1a1a1a", border:"1px solid var(--bz-line-2)", color:"var(--bz-ink-2)", borderRadius:5, width:22, height:22, fontSize:13, cursor:"pointer", fontFamily:"inherit", lineHeight:1, display:"flex", alignItems:"center", justifyContent:"center" }}>+</button>
    </div>
  );

  if (_displayImg) {
    return (
      <div className="boba-card-hover" style={{ aspectRatio:"3/4", perspective:"1000px" }} onMouseMove={onMouseMove} onMouseLeave={onMouseLeave} onMouseEnter={onMouseEnter} onPointerLeave={onMouseLeave} onPointerCancel={onMouseLeave} onTouchEnd={onMouseLeave}>
        <div ref={cardRef} style={{ position:"relative", width:"100%", height:"100%", transition:"transform 0.2s ease, box-shadow 0.2s ease", borderRadius:10, cursor:"pointer", willChange:"transform" }} onClick={handleClick}>
         <div className="boba-flipper" style={{ position:"relative", width:"100%", height:"100%", transformStyle:"preserve-3d", transition:"transform 0.55s cubic-bezier(0.34,1.3,0.5,1)", transform:isFlipped?"rotateY(180deg)":"rotateY(0deg)", willChange:"transform" }}>
          <div style={{ position:"absolute", inset:0, backfaceVisibility:"hidden", WebkitBackfaceVisibility:"hidden", borderRadius:10, overflow:"hidden", border:`2px solid ${isOwned?"#4ade8044":"#1a1a1a"}` }}>
            <img src={_displayImg} alt={c.hero} loading="lazy" decoding="async" style={{ width:"100%", height:"100%", objectFit:"cover", display:"block" }}/>
            {_isScanImg && <div style={{ position:"absolute", top:6, left:6, zIndex:4, background:"rgba(0,0,0,0.7)", border:"1px solid rgba(74,222,128,0.5)", color:"#4ade80", borderRadius:6, padding:"2px 7px", fontSize:9, fontWeight:800, letterSpacing:0.5, backdropFilter:"blur(3px)" }}>📸 Your scan</div>}
            {!_isScanImg && isFoilTreatment && !isIceFoil && <div ref={foilRef} style={{ position:"absolute", inset:0, borderRadius:10, background:"linear-gradient(115deg, transparent 20%, rgba(255,255,255,0.14) 30%, rgba(255,220,100,0.22) 40%, rgba(100,200,255,0.24) 50%, rgba(200,100,255,0.20) 60%, rgba(255,100,150,0.18) 70%, transparent 80%)", backgroundSize:"200% 200%", backgroundPosition:"var(--foilpos,50% 50%)", mixBlendMode:"screen", opacity:0, transition:"opacity 0.2s ease", pointerEvents:"none" }}/>}
            {!_isScanImg && isIceFoil && <div ref={iceRef} style={{ position:"absolute", inset:0, borderRadius:10, backgroundImage:_iceRest(), mixBlendMode:"screen", opacity:0.75, transition:"opacity 0.2s ease", pointerEvents:"none", zIndex:3 }}/>}
            <div ref={glareRef} style={{ position:"absolute", inset:0, borderRadius:10, background:"radial-gradient(ellipse at 50% 50%, rgba(255,255,255,0.22) 0%, transparent 60%)", mixBlendMode:"overlay", opacity:0, transition:"opacity 0.2s ease", pointerEvents:"none" }}/>
            {!_isScanImg && isPixelFoil    && <div ref={pixelRef}    style={{ position:"absolute", inset:0, borderRadius:10, mixBlendMode:"screen", opacity:0, transition:"opacity 0.1s ease", pointerEvents:"none", zIndex:3 }}/>}
            {isMetallicFoil && <div ref={metallicRef} style={{ position:"absolute", inset:0, borderRadius:10, mixBlendMode:"screen", opacity:0, transition:"opacity 0.08s ease", pointerEvents:"none", zIndex:3 }}/>}
            {!onExpand && <div className="boba-flip-pill" style={{ position:"absolute", bottom:6, right:6, display:"flex", alignItems:"center", gap:3, fontSize:10, color:"#fff", fontWeight:700, background:"rgba(0,0,0,0.6)", borderRadius:12, padding:"3px 8px", backdropFilter:"blur(4px)", border:"1px solid rgba(255,255,255,0.15)", pointerEvents:"none" }}>{"\uD83D\uDD04"} flip</div>}
            {toggleOwned && (
              isOwned ? null : (
                <button className="boba-quickadd" onClick={e=>{ e.stopPropagation(); toggleOwned(c.id); onCardActivity&&onCardActivity(); }}
                  title="Add to your collection"
                  style={{ position:"absolute", top:7, right:7, zIndex:6, cursor:"pointer",
                    width:isSmallCard?22:26, height:isSmallCard?22:26, borderRadius:"50%",
                    display:"flex", alignItems:"center", justifyContent:"center",
                    background:"rgba(0,0,0,0.6)", color:"#fff", border:"1.5px solid rgba(255,255,255,0.6)",
                    fontSize:isSmallCard?14:16, fontWeight:700, fontFamily:"inherit",
                    backdropFilter:"blur(3px)", WebkitBackdropFilter:"blur(3px)",
                    boxShadow:"0 2px 6px rgba(0,0,0,0.5)", lineHeight:1 }}>
                  +
                </button>
              )
            )}
          </div>
          <div onPointerDown={()=>onCardActivity&&onCardActivity()} onPointerMove={()=>onCardActivity&&onCardActivity()} onKeyDown={()=>onCardActivity&&onCardActivity()} style={{ position:"absolute", inset:0, backfaceVisibility:"hidden", WebkitBackfaceVisibility:"hidden", transform:"rotateY(180deg)", background:"var(--bz-s1)", border:`2px solid ${isOwned?"#4ade8044":"#2a2a2a"}`, borderRadius:10, padding:isSmallCard?"8px 9px":"12px 14px", display:"flex", flexDirection:"column", justifyContent:"space-between", overflow:"hidden" }}>
            <div style={{ overflowY:"auto", overflowX:"hidden", flex:1, minHeight:0, display:"flex", flexDirection:"column", justifyContent:"space-between" }}>
            <div>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
                <span style={{ fontSize:10, color:"var(--bz-ink-3)" }}>#{c.cardNum}</span>
                <QtyControls/>
              </div>
              <div style={{ fontSize:isSmallCard?12:15, fontWeight:900, color:"var(--bz-ink)", marginBottom:4, lineHeight:1.1 }}>{c.hero}</div>
              {!isSmallCard && <>
              <div style={{ display:"flex", gap:4, flexWrap:"wrap", marginBottom:4 }}>
                {c.weapon && <span style={{ fontSize:10, color:wc, background:wc+"22", borderRadius:4, padding:"1px 6px", fontWeight:700 }}>{c.weapon}</span>}
                {c.treatment && <span style={{ fontSize:10, color:"var(--bz-ink-2)", background:"#1a1a1a", borderRadius:4, padding:"1px 6px" }}>{c.treatment}</span>}
                {c.notation && <span style={{ fontSize:10, color:"#FBBF24", background:"#FBBF2422", borderRadius:4, padding:"1px 6px", fontWeight:700 }}>{c.notation}</span>}
              </div>
              {(c.inspiredBy||c.athlete) && (()=>{
                const ath=c.inspiredBy||c.athlete;
                const sport=athleteSport(ath);
                const sportEmoji={"MLB":"⚾","NFL":"🏈","NBA":"🏀","WNBA":"🏀","NHL":"🏒","PGA":"⛳","WTA":"🎾","ATP":"🎾","Boxing":"🥊","MMA":"🥊","MLS":"⚽","USMNT":"⚽","USWNT":"⚽","Music":"🎤","Acting":"🎬"};
                const emoji=sport?(sport.split(/[\/\s]/).map(s=>sportEmoji[s]).find(Boolean)||"🏅"):"🏅";
                return (
                  <div style={{ fontSize:11, color:"var(--bz-ink-2)", marginTop:4 }}>🏅 Inspired by <strong style={{ color:"var(--bz-ink-2)" }}>{ath}</strong>
                    {sport && <span style={{ display:"inline-flex", alignItems:"center", gap:3, marginLeft:6, background:"rgba(232,49,122,0.12)", border:"1px solid rgba(232,49,122,0.3)", borderRadius:5, padding:"1px 7px", fontSize:10, fontWeight:700, color:"#E8317A", verticalAlign:"middle" }}>{emoji} {sport}</span>}
                  </div>
                );
              })()}
              {(()=>{
                const bio=getPlayerNote(c.hero);
                if(!bio||(!bio.team&&!bio.notes)) return null;
                const longBio = bio.notes && bio.notes.length > 60;
                return (
                  <div style={{ marginTop:6, background:"rgba(255,255,255,0.03)", border:"1px solid rgba(255,255,255,0.07)", borderRadius:7, padding:"7px 9px", position:"relative" }}
                    onMouseEnter={()=>longBio&&setBioOpen(true)} onMouseLeave={()=>setBioOpen(false)}>
                    {bio.team && <div style={{ fontSize:10, fontWeight:700, color:"#7B9CFF", marginBottom:bio.notes?4:0 }}>🏟️ {bio.team}</div>}
                    {bio.notes && <div style={{ fontSize:10, color:"#999", lineHeight:1.4, display:"-webkit-box", WebkitLineClamp:1, WebkitBoxOrient:"vertical", overflow:"hidden", textOverflow:"ellipsis" }}>{bio.notes}</div>}
                    {longBio && <div onClick={e=>{e.stopPropagation();setBioOpen(o=>!o);}} style={{ fontSize:9, color:wc, fontWeight:700, marginTop:4, cursor:"pointer", display:"flex", alignItems:"center", gap:3 }}>📖 {bioOpen?"Close":"Read full bio"}</div>}
                    {bioOpen && longBio && (
                      <div onClick={e=>e.stopPropagation()} style={{ position:"absolute", left:-4, right:-4, bottom:"calc(100% + 6px)", zIndex:100, background:"rgba(12,12,16,0.98)", border:`1.5px solid ${wc}66`, borderRadius:10, padding:"12px 13px", boxShadow:"0 12px 40px rgba(0,0,0,0.7)", backdropFilter:"blur(8px)" }}>
                        {bio.team && <div style={{ fontSize:11, fontWeight:800, color:"#7B9CFF", marginBottom:6 }}>🏟️ {bio.team}</div>}
                        <div style={{ fontSize:11, color:"#ddd", lineHeight:1.55 }}>{bio.notes}</div>
                        {bio.player && <div style={{ fontSize:9, color:"#999", marginTop:8, fontStyle:"italic" }}>Inspired by {bio.player}</div>}
                      </div>
                    )}
                  </div>
                );
              })()}
              {c.variation && <div style={{ fontSize:10, color:"var(--bz-ink-3)" }}>{c.variation}</div>}
              {(() => { const packs = foundInFor(c, foundInMap); if(!packs.length) return null; return <div style={{ display:"inline-flex", alignItems:"center", gap:5, marginTop:6, flexWrap:"wrap" }}><span style={{ color:"var(--bz-ink-3)", fontSize:10, fontWeight:700 }}>Found In:</span>{packs.map(pk => <span key={pk.id} style={{ background:`${pk.color}1a`, border:`1px solid ${pk.color}44`, borderRadius:6, padding:"2px 8px", fontSize:10, fontWeight:700, color:pk.color }}>{pk.label}</span>)}</div>; })()}
              </>}
            </div>
            <div>
              {c.power && <div style={{ fontSize:isSmallCard?16:22, fontWeight:900, color:wc, marginBottom:8 }}>{c.power}{"\u26A1"}</div>}
              <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:6 }}>
                {toggleWant && <button onClick={e=>{e.stopPropagation();toggleWant(c.id);}} style={{ background:isWanted?"#1a0f00":"rgba(255,255,255,0.03)", border:`1px solid ${isWanted?"#FBBF24":"#333"}`, color:isWanted?"#FBBF24":"#999", borderRadius:7, padding:"7px 8px", fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>{isWanted?"\uD83C\uDFAF Wanted":"+ Want"}</button>}
                {onComp && <button onClick={e=>{e.stopPropagation();onComp(c);}} style={{ background:"rgba(123,156,255,0.1)", border:"1px solid rgba(123,156,255,0.3)", color:"#7B9CFF", borderRadius:7, padding:"7px 8px", fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>📊 Comp</button>}
                {onLotEdit && isOwned && <button onClick={e=>{e.stopPropagation();onLotEdit();}} style={{ background:"rgba(232,49,122,0.1)", border:"1px solid rgba(232,49,122,0.3)", color:"#E8317A", borderRadius:7, padding:"7px 8px", fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>💰 Details{lotCount>0?` (${lotCount})`:""}</button>}
                {isAdmin && onImageUpload && (
                  <label onClick={e=>e.stopPropagation()} style={{ background:"rgba(74,222,128,0.1)", border:"1px solid rgba(74,222,128,0.3)", color:"#4ade80", borderRadius:7, padding:"7px 8px", fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"inherit", textAlign:"center" }}>
                    🖼 {c.imageUrl?"Replace":"Add"}
                    <input type="file" accept="image/*" style={{ display:"none" }} onChange={e=>{ const f=e.target.files?.[0]; if(f) onImageUpload(c,f); e.target.value=""; }}/>
                  </label>
                )}
                {isAdmin && onImageClear && c.imageUrl && (
                  <button onClick={e=>{ e.stopPropagation(); if(window.confirm(`Clear the image on ${c.hero}${c.cardNum?` #${c.cardNum}`:""}? This removes the wrong image so you can add the right one.`)) onImageClear(c); }} style={{ background:"rgba(251,191,36,0.1)", border:"1px solid rgba(251,191,36,0.35)", color:"#FBBF24", borderRadius:7, padding:"7px 8px", fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>🧹 Clear Img</button>
                )}
                {isAdmin && onDelete && <button onClick={e=>{e.stopPropagation();onDelete();}} style={{ background:"rgba(239,68,68,0.15)", border:"1px solid rgba(239,68,68,0.4)", color:"#EF4444", borderRadius:7, padding:"7px 8px", fontSize:11, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>🗑 Delete</button>}
              </div>
              <div style={{ display:"flex", justifyContent:"center", alignItems:"center", gap:4, fontSize:10, color:"rgba(255,255,255,0.4)", fontWeight:700, marginTop:8, paddingTop:6, borderTop:"1px solid rgba(255,255,255,0.06)" }}>{"\uD83D\uDD04"} tap to flip back</div>
            </div>
            </div>
          </div>
         </div>
        </div>
      </div>
    );
  }
  return (
    <div onClick={handleClick} style={{ aspectRatio:"3/4", background:isOwned?"#0a1a0a":"#111111", border:`2px solid ${isOwned?"#4ade8044":"#1a1a1a"}`, borderRadius:10, overflow:"hidden", display:"flex", flexDirection:"column", cursor:"pointer" }}>
      {/* "Image coming soon" art placeholder — fills the card-art area */}
      <div style={{ position:"relative", flex:"1 1 58%", minHeight:0, background:`linear-gradient(135deg, ${wc}18, #0a0a0a 70%)`, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", borderBottom:`1px solid ${wc}22` }}>
        <div style={{ fontSize:30, opacity:0.35, marginBottom:6 }}>🃏</div>
        <div style={{ fontSize:9, fontWeight:800, color:"rgba(255,255,255,0.4)", letterSpacing:1.5, textTransform:"uppercase" }}>Image coming soon</div>
        {c.power ? <div style={{ position:"absolute", top:8, right:10, fontSize:13, fontWeight:900, color:wc }}>{c.power}⚡</div> : null}
        {isOwned && <div style={{ position:"absolute", top:6, left:8, fontSize:15 }}>{"\u2705"}</div>}
        {isAdmin && onImageUpload && (
          <label onClick={e=>e.stopPropagation()} style={{ position:"absolute", bottom:8, background:"rgba(74,222,128,0.15)", border:"1px solid rgba(74,222,128,0.35)", color:"#4ade80", borderRadius:6, padding:"2px 10px", fontSize:10, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>
            🖼 Add Image
            <input type="file" accept="image/*" style={{ display:"none" }} onChange={e=>{ const f=e.target.files?.[0]; if(f) onImageUpload(c,f); e.target.value=""; }}/>
          </label>
        )}
      </div>
      {/* Card info */}
      <div style={{ flex:"0 0 auto", padding:"8px 10px", display:"flex", flexDirection:"column", gap:5 }}>
        <div style={{ fontSize:13, fontWeight:900, color:isOwned?"#4ade80":"var(--bz-ink)", lineHeight:1.15, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>{c.hero}</div>
        <div style={{ display:"flex", gap:4, flexWrap:"wrap", alignItems:"center" }}>
          <span style={{ fontSize:9, color:"var(--bz-ink-3)", fontWeight:700 }}>#{c.cardNum}</span>
          {c.weapon && <span style={{ fontSize:9, color:wc, background:wc+"22", borderRadius:4, padding:"1px 5px", fontWeight:700 }}>{c.weapon}</span>}
          {c.treatment && <span style={{ fontSize:9, color:"var(--bz-ink-2)", background:"#1a1a1a", borderRadius:4, padding:"1px 5px" }}>{c.treatment}</span>}
          {c.notation && <span style={{ fontSize:9, color:"#FBBF24", background:"#FBBF2422", borderRadius:4, padding:"1px 5px", fontWeight:700 }}>{c.notation}</span>}
        </div>
        {(() => { const packs = foundInFor(c, foundInMap); if(!packs.length) return null; return <div style={{ display:"inline-flex", alignItems:"center", gap:3, flexWrap:"wrap", alignSelf:"flex-start" }}><span style={{ color:"var(--bz-ink-3)", fontSize:9, fontWeight:700 }}>Found In:</span>{packs.map(pk => <span key={pk.id} style={{ background:`${pk.color}1a`, border:`1px solid ${pk.color}44`, borderRadius:5, padding:"1px 5px", fontSize:9, fontWeight:700, color:pk.color }}>{pk.label}</span>)}</div>; })()}
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:1 }}>
          <div style={{ display:"flex", gap:5, alignItems:"center" }}>
            {toggleWant && <button onClick={e=>{e.stopPropagation();toggleWant(c.id);}} style={{ background:isWanted?"#1a0f00":"transparent", border:`1px solid ${isWanted?"#FBBF24":"#333"}`, color:isWanted?"#FBBF24":"#444", borderRadius:5, padding:"1px 6px", fontSize:10, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>{isWanted?"\uD83C\uDFAF":"+ Want"}</button>}
            {onLotEdit && isOwned && <button onClick={e=>{e.stopPropagation();onLotEdit();}} style={{ background:"rgba(232,49,122,0.1)", border:"1px solid rgba(232,49,122,0.3)", color:"#E8317A", borderRadius:5, padding:"1px 6px", fontSize:10, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>💰{lotCount>0?` ${lotCount}`:""}</button>}
            {isAdmin && onDelete && <button onClick={e=>{e.stopPropagation();onDelete();}} style={{ background:"transparent", border:"1px solid var(--bz-line-2)", color:"#8a8a8a", borderRadius:5, padding:"1px 6px", fontSize:10, cursor:"pointer", fontFamily:"inherit" }} title="Delete card">🗑</button>}
            {/* Kid tag — only on cards you own, and only once you've set up a kid. Cycles through
                Mine → Kid 1 → Kid 2 → Mine, so tagging is a single tap while you're adding cards. */}
            {isOwned && onAssignKid && kidGroups.length>0 && (()=>{
              const qty = parseInt(ownedQty) || 1;
              // Multiple copies can belong to different people, so summarise rather than pretending
              // there's one owner. Tapping cycles ONLY when there's a single copy — with more than
              // one, open the card to tag each copy individually (the tile has no room for that).
              const tags = Array.from({length:qty}, (_,i)=> kidTags?.[i] ?? null);
              const uniq = [...new Set(tags)];
              if (qty > 1) {
                const names = uniq.map(t => t ? (kidGroups.find(k=>k.id===t)?.name || "?") : "Mine");
                const col = uniq.length===1 && uniq[0] ? (kidGroups.find(k=>k.id===uniq[0])?.color||"#888") : "#888";
                return (
                  <span title="Open the card to tag each copy"
                    style={{ background:"transparent", border:`1px solid ${col}55`, color:col, borderRadius:5, padding:"1px 6px", fontSize:10, fontWeight:700, whiteSpace:"nowrap", maxWidth:92, overflow:"hidden", textOverflow:"ellipsis" }}>
                    🧒 {names.join(" + ")}
                  </span>
                );
              }
              const cur = tags[0];
              const g = kidGroups.find(k=>k.id===cur);
              const next = () => {
                const i = kidGroups.findIndex(k=>k.id===cur);
                return i === -1 ? kidGroups[0].id : (i === kidGroups.length-1 ? null : kidGroups[i+1].id);
              };
              return (
                <button onClick={e=>{e.stopPropagation(); onAssignKid(c.id, next(), 0);}}
                  title={g?`${g.name}'s card — tap to change`:"Tap to tag this card to a kid"}
                  style={{ background:g?`${g.color}22`:"transparent", border:`1px solid ${g?g.color:"#333"}`, color:g?g.color:"#444", borderRadius:5, padding:"1px 6px", fontSize:10, fontWeight:700, cursor:"pointer", fontFamily:"inherit", whiteSpace:"nowrap", maxWidth:78, overflow:"hidden", textOverflow:"ellipsis" }}>
                  {g ? `🧒 ${g.name}` : "🧒"}
                </button>
              );
            })()}
            {/* Sold / traded away — drops it from the active collection but keeps the record. */}
            {isOwned && onSell && (
              <button onClick={e=>{e.stopPropagation(); onSell();}} title="Sold, traded, or gave this away"
                style={{ background:"transparent", border:"1px solid #333", color:"#444", borderRadius:5, padding:"1px 6px", fontSize:10, fontWeight:700, cursor:"pointer", fontFamily:"inherit" }}>↗</button>
            )}
          </div>
          <QtyControls/>
        </div>
      </div>
    </div>
  );
}

// PERF: the card grid renders 100+ tiles. Without memo, flipping/hovering ONE card re-rendered
// EVERY tile (because flippedCard lives in the parent), rebuilding all their DOM + animations.
// This comparator makes a tile re-render only when something about THAT tile actually changed —
// notably, flippedCard only matters if it involves this card.
const BobaCard = React.memo(BobaCardImpl, (prev, next) => {
  if (prev.c !== next.c) return false;
  if (prev.isOwned !== next.isOwned) return false;
  if (prev.ownedQty !== next.ownedQty) return false;
  if (prev.isAdmin !== next.isAdmin) return false;
  if (prev.lotCount !== next.lotCount) return false;
  if (prev.myScanPhoto !== next.myScanPhoto) return false;
  // Which packs a card is found in. Without this the memo skips the re-render and the badge
  // keeps showing stale data even though the live map has already updated.
  if (prev.foundInMap !== next.foundInMap) return false;
  // Compare by VALUE. These are small arrays, and comparing by reference meant a
  // fresh-but-identical array (exactly what a `= []` default prop yields on every render)
  // re-rendered every card in the grid for no reason — thousands of wasted renders.
  const kgPrev = prev.kidGroups || [], kgNext = next.kidGroups || [];
  if (kgPrev.length !== kgNext.length || kgPrev.some((g,i)=>g!==kgNext[i])) return false;
  const ktPrev = prev.kidTags || [], ktNext = next.kidTags || [];
  if (ktPrev.length !== ktNext.length || ktPrev.some((t,i)=>t!==ktNext[i])) return false;
  // Want status for THIS card only.
  const id = next.c?.id;
  if ((prev.wantList?.[id] ? 1 : 0) !== (next.wantList?.[id] ? 1 : 0)) return false;
  // Flip state only matters if this card is (or was) the flipped one.
  const wasFlipped = prev.flippedCard === id;
  const isFlipped  = next.flippedCard === id;
  if (wasFlipped !== isFlipped) return false;
  return true; // otherwise: skip the re-render
});

