  "WADDLER": { player:"Jaylen Waddle", team:"Miami Dolphins", notes:"One of the fastest receivers in football. Set a rookie reception record and forms half of Miami's electric receiver duo. A big-play machine.", lines:["\"Game-breaking speed — one of the fastest men in the NFL\""] },
  "BURROCIOUS": { player:"Joe Burrow", team:"Cincinnati Bengals", notes:"Heisman winner, #1 overall pick, and the QB who led the Bengals back to the Super Bowl. Ice-cold under pressure with elite accuracy.", lines:["\"Joe Cool — a Heisman, a #1 pick, and a Super Bowl run\""] },
  "GRAND-MA-MA": { player:"Larry Johnson", team:"Kansas City Chiefs", notes:"A bruising power back who set the single-season carries record. 2x Pro Bowler who carried the Chiefs' offense on his back.", lines:["\"A workhorse who set the record for carries in a season\""] },
  "EXTERMINABER": { player:"Malik Nabers", team:"New York Giants", notes:"Record-setting rookie receiver out of LSU. Led the Giants in every receiving category as a rookie and is already one of the most dynamic young WRs in football.", lines:["\"A rookie season for the ages — the Giants' new star\""] },
  "XL": { player:"Xavier Legette", team:"Carolina Panthers", notes:"Explosive young receiver and a first-round pick. A big, physical playmaker for Carolina's developing offense.", lines:["\"A big, fast playmaker on the rise in Carolina\""] },
  "Gaveler": { player:"Aaron Judge", team:"New York Yankees", notes:"3x AL MVP and the captain of the Yankees. Set the AL single-season home run record with 62. A towering, generational slugger and the face of baseball.", lines:["\"62 home runs — the AL record. The Judge holds court.\"","\"A three-time MVP and the captain of the Yankees\""] },
  "Cruschman": { player:"Adley Rutschman", team:"Baltimore Orioles", notes:"#1 overall pick and All-Star catcher who became the cornerstone of Baltimore's revival. A switch-hitting leader behind the plate.", lines:["\"The #1 pick who revived the Orioles\""] },
  "Goofin' Off": { player:"Adrián Beltré", team:"Texas Rangers", notes:"Hall of Famer with over 3,000 hits and 477 home runs. One of the greatest defensive third basemen ever — and the most fun player in baseball, famous for hating his head being touched.", lines:["\"3,000 hits, a Gold Glove magician, and the most fun player ever\""] },
  "Awesome Dawson": { player:"Andre Dawson", team:"Montreal Expos", notes:"The Hawk. Hall of Famer, 1987 NL MVP, 8x All-Star. A five-tool legend who did it all on bad knees. One of the most respected players of his era.", lines:["\"The Hawk — an MVP and Hall of Famer who played through anything\""] },
  "Clutch": { player:"Andrew McCutchen", team:"Pittsburgh Pirates", notes:"2013 NL MVP and the face of the Pirates' resurgence. 5x All-Star and one of the most beloved players in Pittsburgh history.", lines:["\"Cutch — an MVP and the heart of Pittsburgh baseball\""] },
  "Curaçao Kid": { player:"Andruw Jones", team:"Atlanta Braves", notes:"One of the greatest defensive center fielders ever — 10 straight Gold Gloves. A power-hitting force who once hit 51 homers in a season.", lines:["\"The greatest defensive center fielder of his generation\""] },
  "Bern Baby, Bern": { player:"Bernie Williams", team:"New York Yankees", notes:"4x World Series champion and the elegant center fielder of the Yankees dynasty. 5x All-Star, batting champion, and an accomplished jazz guitarist.", lines:["\"Four rings in center field for the Yankees dynasty\""] },
  "Gigawitt": { player:"Bobby Witt Jr.", team:"Kansas City Royals", notes:"2x All-Star, 2x Gold Glover, and a batting champion. The franchise cornerstone of the Royals and one of the best all-around shortstops in baseball — power, speed, and defense.", lines:["\"The best all-around shortstop in baseball — and a Royals lifer\""] },
  "Rook": { player:"Brent Rooker", team:"Athletics", notes:"All-Star slugger who broke out as one of the most productive power hitters in the American League. A waiver-claim success story.", lines:["\"From waiver claim to All-Star slugger\""] },
  "Harpoon": { player:"Bryce Harper", team:"Philadelphia Phillies", notes:"2x NL MVP and the face of the Phillies. A #1 overall pick at 17 who became a generational superstar and a fearsome October performer.", lines:["\"Two MVPs and one of the most electric players of his era\""] },
  "BuckShot": { player:"Buck Showalter", team:"Baltimore Orioles", notes:"3x Manager of the Year who revived multiple franchises. One of the sharpest baseball minds of his generation.", lines:["\"A three-time Manager of the Year and master tactician\""] },
  "Alien": { player:"CJ Abrams", team:"Washington Nationals", notes:"All-Star shortstop with rare speed and power. A dynamic young building block for the Nationals.", lines:["\"Speed, power, and star potential up the middle\""] },
  "Dumper": { player:"Cal Raleigh", team:"Seattle Mariners", notes:"Big Dumper. All-Star catcher who set the single-season home run record for a catcher. A switch-hitting power source and Seattle fan favorite.", lines:["\"Big Dumper — the most home runs ever by a catcher in a season\""] },
  "The Ironman": { player:"Cal Ripken Jr.", team:"Baltimore Orioles", notes:"The Iron Man. Played 2,632 consecutive games — a record that may never fall. 2x MVP, 19x All-Star, Hall of Famer who redefined the shortstop position.", lines:["\"2,632 straight games — the most unbreakable record in sports\"","\"The Iron Man redefined what shortstops could be\""] },
  "Bionic": { player:"Carlos Correa", team:"Houston Astros", notes:"World Series champion, Rookie of the Year, and All-Star shortstop. A clutch postseason performer and defensive standout.", lines:["\"A World Series champ and Rookie of the Year at short\""] },
  "Pudge": { player:"Carlton Fisk", team:"Boston Red Sox", notes:"Hall of Fame catcher famous for waving the 1975 World Series walk-off homer fair — one of baseball's most iconic moments. 11x All-Star.", lines:["\"That wave — one of the most iconic moments in World Series history\""] },
  "Carroller": { player:"Corbin Carroll", team:"Arizona Diamondbacks", notes:"Rookie of the Year and All-Star outfielder. A five-tool speedster who powered the Diamondbacks to a pennant. One of the brightest young stars in the game.", lines:["\"Rookie of the Year and a five-tool electric talent\""] },
  "Cowboy": { player:"Corey Seager", team:"Texas Rangers", notes:"2x World Series MVP — one of only a few players ever to win it twice. A premier power-hitting shortstop and October legend.", lines:["\"Two World Series MVPs — a true October legend\""] },
  "Big Geo": { player:"Craig Biggio", team:"Houston Astros", notes:"Hall of Famer with over 3,000 hits. 7x All-Star who played catcher, second base, AND outfield at an elite level. The ultimate Astros lifer.", lines:["\"3,000 hits and a Hall of Fame career all in Houston\""] },
  "Lieutenant": { player:"Dansby Swanson", team:"Chicago Cubs", notes:"#1 overall pick, World Series champion, and Gold Glove shortstop. A steady defensive leader and clutch contributor.", lines:["\"A #1 pick, a World Series ring, and Gold Glove defense\""] },
  "Smoke": { player:"Dave Stewart", team:"Oakland Athletics", notes:"World Series MVP and one of the most feared big-game pitchers of his era. Won 20+ games four straight years and owned October.", lines:["\"The most intimidating big-game pitcher of his era\""] },
